205: // getCgroupConfigInternal are the pieces of getCgroupConfig that don't require the cm object.
206: // This is added to unit test without needing to create a full containerManager
207: func getCgroupConfigInternal(rl v1.ResourceList, compressibleResourcesOnly bool) *ResourceConfig {
208: 	// TODO(vishh): Set CPU Quota if necessary.
209: 	if rl == nil {
210: 		return nil
211: 	}
212: 	var rc ResourceConfig
213: 
214: 	setCompressibleResources := func() {
215: 		if q, exists := rl[v1.ResourceCPU]; exists {
216: 			// CPU is defined in milli-cores.
217: 			val := MilliCPUToShares(q.MilliValue())
218: 			rc.CPUShares = &val
219: 		}
220: 	}
221: 
222: 	// Only return compressible resources
223: 	if compressibleResourcesOnly {
224: 		setCompressibleResources()
225: 	} else {
226: 		if q, exists := rl[v1.ResourceMemory]; exists {
227: 			// Memory is defined in bytes.
228: 			val := q.Value()
229: 			rc.Memory = &val
230: 		}
231: 
232: 		setCompressibleResources()
233: 
234: 		if q, exists := rl[pidlimit.PIDs]; exists {
235: 			val := q.Value()
236: 			rc.PidsLimit = &val
237: 		}
238: 		rc.HugePageLimit = HugePageLimits(rl)
239: 	}
240: 	return &rc
241: }
