272: // it also includes internal resources (currently process IDs).  It is intended for setting
273: // up top level cgroups only.
274: func (cm *containerManagerImpl) getNodeAllocatableInternalAbsolute() v1.ResourceList {
275: 	return cm.getNodeAllocatableAbsoluteImpl(cm.internalCapacity)
