278: // GetNodeAllocatableReservation returns amount of compute or storage resource that have to be reserved on this node from scheduling.
279: func (cm *containerManagerImpl) GetNodeAllocatableReservation() v1.ResourceList {
280: 	cm.RLock()
281: 	defer cm.RUnlock()
282: 	evictionReservation := hardEvictionReservation(cm.HardEvictionThresholds, cm.capacity)
283: 	result := make(v1.ResourceList)
284: 	for k := range cm.capacity {
285: 		value := resource.NewQuantity(0, resource.DecimalSI)
286: 		if cm.NodeConfig.SystemReserved != nil {
287: 			value.Add(cm.NodeConfig.SystemReserved[k])
288: 		}
289: 		if cm.NodeConfig.KubeReserved != nil {
290: 			value.Add(cm.NodeConfig.KubeReserved[k])
291: 		}
292: 		if evictionReservation != nil {
293: 			value.Add(evictionReservation[k])
294: 		}
295: 		if !value.IsZero() {
296: 			result[k] = *value
297: 		}
298: 	}
299: 	return result
300: }
